#include<bits/stdc++.h>
using namespace std;
constexpr int N=1e6+10;
int now[N],cnt;
bool vis[N];
class FHQ_Treap
{
    public:
    struct node
    {
        int l,r;
        int val,key;
        int siz;
        long long sum;
    }t[N];
    int root,tot;
    public:
    int newnode(int v)
    {
        t[++tot].val=v;
        t[tot].key=rand();
        t[tot].siz=1;
        t[tot].sum=v;
        return tot;
    }
    void pushup(int x)
    {
        t[x].siz=t[t[x].l].siz+t[t[x].r].siz+1;
        t[x].sum=t[t[x].l].sum+t[t[x].r].sum+t[x].val;
    }
    void split(int p,int v,int &x,int &y)
    {
        if(p==0)
        {
            x=y=0;
            return;
        }
        if(t[p].val<=v)
        {
            x=p;
            split(t[x].r,v,t[x].r,y);
        }
        else
        {
            y=p;
            split(t[y].l,v,x,t[y].l);
        }
        pushup(p);
    }
    int merge(int x,int y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        if(t[x].key<t[y].key)
        {
            t[x].r=merge(t[x].r,y);
            pushup(x);
            return x;
        }
        else
        {
            t[y].l=merge(x,t[y].l);
            pushup(y);
            return y;
        }
    }
    void insert(int v)
    {
        int x,y,z;
        split(root,v,x,y);
        z=newnode(v);
        root=merge(merge(x,z),y);
    }
    void del(int v)
    {
        int x,y,z;
        split(root,v,x,z);
        split(x,v-1,x,y);
        y=merge(t[y].l,t[y].r);
        root=merge(merge(x,y),z);
    }
    void update(int p,int v)
    {
        if(vis[p])
        {
            del(now[p]);
        }
        else
        {
            vis[p]=true;
            cnt--;
        }
        now[p]=v;
        insert(now[p]);
    }
    int querycnt(int s)
    {
        int x,y;
        split(root,s,x,y);
        int ans=t[x].siz;
        root=merge(x,y);
        return ans;
    }
    long long querysum(int s)
    {
        int x,y;
        split(root,s,x,y);
        long long ans=t[x].sum;
        root=merge(x,y);
        return ans;
    }
}t;
long long readint()
{
    char ch=getchar_unlocked();
    long long x=0;
    while(!isdigit(ch))
    {
        ch=getchar_unlocked();
    }
    while(isdigit(ch))
    {
        x=(x<<3)+(x<<1)+(ch-'0');
        ch=getchar_unlocked();
    }
    return x;
}
char readchar()
{
    char ch=getchar_unlocked();
    while(ch!='U'&&ch!='Z')
    {
        ch=getchar_unlocked();
    }
    return ch;
}
int main()
{
    int n=readint(),m=readint();
    cnt=n;
    while(m--)
    {
        char op=readchar();
        int x=readint(),y=readint();
        if(op=='U')
        {
            t.update(x,y);
        }
        else
        {
            int c=x,s=y;
            int cnt=::cnt+t.querycnt(s);
            long long sum=t.querysum(s);
            // printf("cnt=%d sum=%d\n",cnt,sum);
            if(1ll*(n-cnt)*s+sum>=1ll*c*s)
            {
                printf("TAK\n");
            }
            else
            {
                printf("NIE\n");
            }
        }
    }
    return 0;
}
